import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableDays, setAvailableDays] = useState([]);
  const [availableTimes, setAvailableTimes] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  // ✅ FEEDBACK STATES
  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  // ✅ FETCH DOCTOR
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableDays(data.doctor.available_days || []);
        setAvailableTimes(data.doctor.available_time_slots || []);
      })
      .catch((err) => console.error(err));
  }, [doctor_id]);

  // ✅ FETCH FEEDBACKS
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data))
      .catch((err) => console.error(err));
  }, [doctor_id]);

  // ✅ GET DAY NAME
  const getDayName = (dateStr) => {
    return new Date(dateStr).toLocaleDateString("en-US", {
      weekday: "long",
    });
  };

  // ✅ DATE VALIDATION
  const handleDateChange = (e) => {
    const selectedDate = e.target.value;
    const dayName = getDayName(selectedDate);

    if (!availableDays.includes(dayName)) {
      alert(`Doctor not available on ${dayName}`);
      setDate("");
      return;
    }

    setDate(selectedDate);
  };

  // ✅ NEXT BUTTON
  const handleNext = () => {
    if (!date || !time) {
      alert("Please select date and time");
      return;
    }

    navigate("/appointment", {
      state: {
        doctor,
        date,
        time,
        doctor_id,
      },
    });
  };

  // ✅ SUBMIT FEEDBACK
  const handleSubmitFeedback = () => {
    if (!rating || !comment) {
      alert("Please add rating and comment");
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
      })
      .catch((err) => console.error(err));
  };

  // ✅ LOADING
  if (!doctor) {
    return <h2 style={styles.loading}>Loading...</h2>;
  }

  return (
    <div style={styles.container}>
      <Navbar />

      <div style={styles.main}>
        <div style={styles.card}>
          
          {/* IMAGE */}
          <div style={styles.left}>
            <img
              src={
                doctor.image
                  ? doctor.image
                  : "https://cdn-icons-png.flaticon.com/512/387/387561.png"
              }
              alt={doctor.name}
              style={styles.image}
            />
          </div>

          {/* DETAILS */}
          <div style={styles.right}>
            <h2>{doctor.name}</h2>

            <p><b>Specialization:</b> {doctor.field}</p>
            <p><b>Experience:</b> {doctor.experience}</p>
            <p><b>Qualification:</b> {doctor.qualification}</p>

            <p>
              <b>Available Days:</b> {availableDays.join(", ")}
            </p>

            {/* BOOKING */}
            <div style={styles.bookingSection}>
              <label>Select Date:</label>
              <input
                type="date"
                value={date}
                min={new Date().toISOString().split("T")[0]}
                onChange={handleDateChange}
                style={styles.input}
              />

              <label>Select Time:</label>
              <select
                value={time}
                onChange={(e) => setTime(e.target.value)}
                style={styles.input}
              >
                <option value="">Select Time</option>
                {availableTimes.length > 0 ? (
                  availableTimes.map((t, index) => (
                    <option key={index} value={t}>
                      {t}
                    </option>
                  ))
                ) : (
                  <option disabled>No time slots available</option>
                )}
              </select>

              <button style={styles.button} onClick={handleNext}>
                Book Appointment
              </button>
            </div>

            {/* ✅ FEEDBACK SECTION */}
            <div style={{ marginTop: "30px" }}>
              <h3>Patient Reviews</h3>

              {/* ADD REVIEW */}
              <select
                value={rating}
                onChange={(e) => setRating(e.target.value)}
                style={styles.input}
              >
                <option value="">Select Rating</option>
                <option value="5">⭐⭐⭐⭐⭐</option>
                <option value="4">⭐⭐⭐⭐</option>
                <option value="3">⭐⭐⭐</option>
                <option value="2">⭐⭐</option>
                <option value="1">⭐</option>
              </select>

              <textarea
                placeholder="Write your feedback..."
                value={comment}
                onChange={(e) => setComment(e.target.value)}
                style={{ ...styles.input, height: "80px" }}
              />

              <button onClick={handleSubmitFeedback} style={styles.button}>
                Submit Feedback
              </button>

              {/* SHOW REVIEWS */}
              <div style={{ marginTop: "20px" }}>
                {feedbacks.length > 0 ? (
                  feedbacks.map((fb) => (
                    <div
                      key={fb.id}
                      style={{
                        borderBottom: "1px solid #ddd",
                        padding: "10px 0",
                      }}
                    >
                      <p><b>{fb.user_name}</b></p>
                      <p>{"⭐".repeat(fb.rating)}</p>
                      <p>{fb.comment}</p>
                    </div>
                  ))
                ) : (
                  <p>No reviews yet</p>
                )}
              </div>
            </div>

          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* ✅ STYLES */
const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    minHeight: "100vh",
    backgroundColor: "#f4f6f9",
    fontFamily: "Arial, sans-serif",
  },
  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
  },
  card: {
    display: "flex",
    backgroundColor: "#fff",
    borderRadius: "10px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
    padding: "30px",
    width: "750px",
    gap: "30px",
  },
  left: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
  image: {
    width: "150px",
    height: "150px",
    borderRadius: "50%",
    objectFit: "cover",
  },
  right: {
    flex: 1,
  },
  bookingSection: {
    marginTop: "20px",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },
  input: {
    padding: "8px",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },
  button: {
    marginTop: "10px",
    padding: "10px",
    backgroundColor: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
  loading: {
    textAlign: "center",
    marginTop: "50px",
  },
};
